def get_data():
    url = request.args.get('url', '')
    params = {}
    
    for key, value in request.args.items():
        if key != 'url':
            params[key] = value
    
    cached_data = cache.get(url, params)
    
    if cached_data:
        return jsonify({
            'cached': True,
            'data': cached_data
        })
    
    api_data = expensive_api_call(url, params)
